import { useState } from "react";

const FRAMEWORKS = ["NIST SP 800-53", "NIST CSF 2.0", "FedRAMP", "CIS Controls v8"];
const ENVS = ["AWS", "Azure", "GCP", "Multi-cloud"];

const styles = `
  body { background: #2c2418; }
  .assess-btn { background: #c17f3a; color: #f0e6d0; border: none; transition: background 0.2s; }
  .assess-btn:hover:not(:disabled) { background: #8a7a5a; }
  .assess-btn:disabled { background: #3a3028; color: #6a5a4a; cursor: not-allowed; }
  .nist-tag { display: inline-block; font-size: 12px; font-family: monospace; padding: 3px 10px; border-radius: 99px; background: #2a3a38; border: 1px solid #c17f3a; color: #6eccc0; text-decoration: none; transition: background 0.2s, color 0.2s, border-color 0.2s; cursor: pointer; }
  .nist-tag:hover { background: #4a3e2e; color: #e0c090; border-color: #a08858; }
  textarea:focus { outline: none; border-color: #c17f3a !important; }
  select option { background: #2c2418; }
`;

export default function App() {
  const [input, setInput] = useState("");
  const [env, setEnv] = useState("AWS");
  const [framework, setFramework] = useState("NIST SP 800-53");
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState(null);
  const [error, setError] = useState("");

  async function assess() {
    setError("");
    setResult(null);
    setLoading(true);
    try {
      const res = await fetch("https://api.anthropic.com/v1/messages", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          "x-api-key": process.env.REACT_APP_ANTHROPIC_API_KEY,
          "anthropic-version": "2023-06-01",
          "anthropic-dangerous-direct-browser-access": "true"
        },
        body: JSON.stringify({
          model: "claude-sonnet-4-6",
          max_tokens: 4000,
          system: "You are a senior GRC analyst for " + env + " environments using " + framework + ". Return ONLY valid JSON (no markdown) with keys: assessmentQuestions (array), evidenceToCollect (array), potentialWeaknesses (array of {name, description, severity}), nistControls (array of {id, name, rationale}). Be specific to " + env + ".",
          messages: [{ role: "user", content: "Assess this security control:\n\n" + input }]
        })
      });
      const data = await res.json();
      if (data.error) throw new Error(data.error.message);
      const text = data.content.find(function(b) { return b.type === "text"; })?.text || "";
      setResult(JSON.parse(text.replace(/```json|```/g, "").trim()));
    } catch (e) {
      setError(e.message);
    }
    setLoading(false);
  }

  return (
    <>
      <style>{styles}</style>
      <div style={{ minHeight: "100vh", background: "#2c2418", color: "#e0d0b8", fontFamily: "system-ui, sans-serif", padding: "2rem 1rem" }}>
        <div style={{ maxWidth: 760, margin: "0 auto" }}>

          <span style={{ fontSize: 11, background: "#2a3a38", color: "#c8a060", padding: "3px 12px", borderRadius: 99, fontWeight: 600, letterSpacing: "0.06em", border: "1px solid #5a4a2a" }}>
            GRC PORTFOLIO TOOL
          </span>

          <h1 style={{ fontSize: 28, fontWeight: 700, margin: "0.75rem 0 0.25rem", color: "#f0e0c0" }}>
            Security Control Assessor
          </h1>
          <p style={{ color: "#8a7a60", marginBottom: "1.75rem", fontSize: 14 }}>
            Powered by Claude AI · Assessment questions, evidence checklists, weaknesses & {framework} mappings
          </p>

          <div style={{ background: "#352a1a", border: "1px solid #4a3a22", borderRadius: 12, padding: "1.25rem", marginBottom: "1rem" }}>
            <label style={{ fontSize: 11, fontWeight: 600, color: "#8a7a60", display: "block", marginBottom: 8, letterSpacing: "0.06em" }}>
              CONTROL DESCRIPTION OR SYSTEM DETAIL
            </label>
            <textarea
              value={input}
              onChange={function(e) { setInput(e.target.value); }}
              placeholder="Example: Our AWS environment uses IAM roles with least-privilege for EC2. MFA is enforced on root and all IAM users..."
              style={{ width: "100%", minHeight: 130, padding: "0.75rem", borderRadius: 8, border: "1px solid #4a3a22", fontSize: 14, resize: "vertical", fontFamily: "inherit", boxSizing: "border-box", background: "#251e12", color: "#e0d0b8" }}
            />
            <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 10, marginTop: 10 }}>
              <div>
                <label style={{ fontSize: 11, color: "#8a7a60", display: "block", marginBottom: 4, letterSpacing: "0.06em" }}>CLOUD ENVIRONMENT</label>
                <select value={env} onChange={function(e) { setEnv(e.target.value); }}
                  style={{ width: "100%", padding: "0.5rem 0.75rem", borderRadius: 8, border: "1px solid #4a3a22", fontSize: 13, background: "#251e12", color: "#e0d0b8" }}>
                  {ENVS.map(function(e) { return <option key={e}>{e}</option>; })}
                </select>
              </div>
              <div>
                <label style={{ fontSize: 11, color: "#8a7a60", display: "block", marginBottom: 4, letterSpacing: "0.06em" }}>COMPLIANCE FRAMEWORK</label>
                <select value={framework} onChange={function(e) { setFramework(e.target.value); }}
                  style={{ width: "100%", padding: "0.5rem 0.75rem", borderRadius: 8, border: "1px solid #4a3a22", fontSize: 13, background: "#251e12", color: "#e0d0b8" }}>
                  {FRAMEWORKS.map(function(f) { return <option key={f}>{f}</option>; })}
                </select>
              </div>
            </div>
            <button
              onClick={assess}
              disabled={loading || !input.trim()}
              className="assess-btn"
              style={{ width: "100%", marginTop: 12, padding: "0.7rem", borderRadius: 8, fontSize: 14, fontWeight: 600, cursor: "pointer" }}>
              {loading ? "Analyzing..." : "Assess control"}
            </button>
          </div>

          {error && (
            <div style={{ background: "#2a1a1a", border: "1px solid #5a2a2a", borderRadius: 8, padding: "0.75rem 1rem", color: "#c07070", fontSize: 13, marginBottom: "1rem" }}>
              {error}
            </div>
          )}

          {result && <Results result={result} framework={framework} />}
        </div>
      </div>
    </>
  );
}

function Results({ result, framework }) {
  function sevColor(s) {
    if (s === "High") return { bg: "#2a1a1a", color: "#c07878", border: "#5a2a2a" };
    if (s === "Medium") return { bg: "#2a2010", color: "#c0a060", border: "#5a4010" };
    return { bg: "#1a2a1a", color: "#70a870", border: "#2a5a2a" };
  }

  return (
    <div style={{ display: "flex", flexDirection: "column", gap: "0.75rem" }}>
      <Card title="Assessment questions" icon="?" accent="#6a8a70">
        <ul style={{ paddingLeft: "1.25rem", display: "flex", flexDirection: "column", gap: 8 }}>
          {result.assessmentQuestions.map(function(q, i) {
            return <li key={i} style={{ fontSize: 13, lineHeight: 1.7, color: "#b0a090" }}>{q}</li>;
          })}
        </ul>
      </Card>

      <Card title="Evidence to collect" icon="+" accent="#6a7a8a">
        <ul style={{ paddingLeft: "1.25rem", display: "flex", flexDirection: "column", gap: 8 }}>
          {result.evidenceToCollect.map(function(e, i) {
            return <li key={i} style={{ fontSize: 13, lineHeight: 1.7, color: "#b0a090" }}>{e}</li>;
          })}
        </ul>
      </Card>

      <Card title="Potential weaknesses" icon="!" accent="#8a6a5a">
        {result.potentialWeaknesses.map(function(w, i) {
          var s = sevColor(w.severity);
          return (
            <div key={i} style={{ padding: "0.75rem 0", borderBottom: i < result.potentialWeaknesses.length - 1 ? "1px solid #2a3a38" : "none" }}>
              <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 4 }}>
                <span style={{ fontSize: 13, fontWeight: 600, color: "#f0e0c0" }}>{w.name}</span>
                <span style={{ fontSize: 11, fontWeight: 600, padding: "2px 8px", borderRadius: 99, background: s.bg, color: s.color, border: "1px solid " + s.border, marginLeft: "auto" }}>
                  {w.severity}
                </span>
              </div>
              <p style={{ fontSize: 12, color: "#7a6a50", lineHeight: 1.6, margin: 0 }}>{w.description}</p>
            </div>
          );
        })}
      </Card>

      <Card title={framework + " control mappings"} icon="#" accent="#7a6a8a">
        <div style={{ display: "flex", flexWrap: "wrap", gap: 8, marginBottom: 12 }}>
          {result.nistControls.map(function(c, i) {
            return (
              <a key={i} className="nist-tag" href={"https://csrc.nist.gov/projects/cprt/catalog#/cprt/framework/version/SP_800_53_5_1_0/home?element=" + c.id} target="_blank" rel="noreferrer">
                {c.id}
              </a>
            );
          })}
        </div>
        <ul style={{ paddingLeft: "1.25rem", display: "flex", flexDirection: "column", gap: 8 }}>
          {result.nistControls.map(function(c, i) {
            return (
              <li key={i} style={{ fontSize: 13, lineHeight: 1.7, color: "#b0a090" }}>
                <strong style={{ color: "#e0d0b8" }}>{c.id} - {c.name}:</strong> {c.rationale}
              </li>
            );
          })}
        </ul>
      </Card>
    </div>
  );
}

function Card({ title, icon, accent, children }) {
  return (
    <div style={{ background: "#352a1a", border: "1px solid #4a3a22", borderRadius: 12, overflow: "hidden" }}>
      <div style={{ display: "flex", alignItems: "center", gap: 10, padding: "0.85rem 1.25rem", borderBottom: "1px solid #4a3a22", borderLeft: "3px solid " + accent }}>
        <span style={{ fontSize: 14, color: accent, fontWeight: 700 }}>{icon}</span>
        <span style={{ fontSize: 12, fontWeight: 700, color: "#d0c0a0", letterSpacing: "0.05em" }}>{title.toUpperCase()}</span>
      </div>
      <div style={{ padding: "1rem 1.25rem" }}>{children}</div>
    </div>
  );
}
